#include <stdio.h>
#include <math.h>
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int angles[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &angles[i]);
        }
        int g = angles[1] - angles[0];
        for (int i = 2; i < n; i++) {
            g = gcd(g, angles[i] - angles[i-1]);
        }
        int total_slices = 360 / g;
        int additional_cuts = total_slices - n;
        printf("%d\n", additional_cuts);
    }
    return 0;
}

