import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] angles = new int[n];
            for (int i = 0; i < n; i++) {
                angles[i] = sc.nextInt();
            }
            int g = angles[1] - angles[0];
            for (int i = 2; i < n; i++) {
                g = gcd(g, angles[i] - angles[i-1]);
            }
            int total_slices = 360 / g;
            int additional_cuts = total_slices - n;
            System.out.println(additional_cuts);
        }
    }
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}

